import {
    DockviewApi,
    DockviewReact,
    DockviewReadyEvent,
    DockviewTheme,
    IDockviewPanelProps,
    themeAbyss,
    TabAnimation,
} from 'dockview-react';
import * as React from 'react';

const Default = (props: IDockviewPanelProps) => {
    return (
        <div style={{ height: '100%' }}>
            <div>{props.api.title}</div>
        </div>
    );
};

const components = {
    default: Default,
};

const Component = (props: { theme?: string }) => {
    const [api, setApi] = React.useState<DockviewApi>();
    const [tabAnimation, setTabAnimation] = React.useState<TabAnimation>('default');

    const theme: DockviewTheme = React.useMemo(
        () => ({ ...themeAbyss, tabAnimation }),
        [tabAnimation]
    );

    const toggleMode = () => {
        setTabAnimation((prev) => (prev === 'smooth' ? 'default' : 'smooth'));
    };

    React.useEffect(() => {
        if (!api) {
            return;
        }

        const disposables = [
            api.onWillShowOverlay((e) => {
                if (e.kind === 'header_space' || e.kind === 'tab') {
                    return;
                }
                e.preventDefault();
            }),
        ];

        return () => {
            disposables.forEach((disposable) => {
                disposable.dispose();
            });
        };
    }, [api]);

    const onReady = (event: DockviewReadyEvent) => {
        setApi(event.api);

        event.api.addPanel({
            id: 'panel_1',
            component: 'default',
        });

        event.api.addPanel({
            id: 'panel_2',
            component: 'default',
        });

        event.api.addPanel({
            id: 'panel_3',
            component: 'default',
        });
        event.api.addPanel({
            id: 'panel_4',
            component: 'default',
        });
        event.api.addPanel({
            id: 'panel_5',
            component: 'default',
        });
    };

    return (
        <div
            style={{
                height: '100%',
                display: 'flex',
                flexDirection: 'column',
            }}
        >
            <div
                style={{
                    padding: '4px 8px',
                    display: 'flex',
                    alignItems: 'center',
                    gap: '8px',
                }}
            >
                <button onClick={toggleMode}>
                    {`tabAnimation: ${tabAnimation}`}
                </button>
            </div>
            <div style={{ flexGrow: 1 }}>
                <DockviewReact
                    className={`${props.theme || 'dockview-theme-abyss'}`}
                    onReady={onReady}
                    components={components}
                    theme={theme}
                    disableFloatingGroups={true}
                />
            </div>
        </div>
    );
};

export default Component;
